// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/terminate-instances/result`);
  const configBody = await configGet.json();

  if (!configBody.TerminatingInstances || configBody.TerminatingInstances.length === 0) {
    console.log("EC2 instance termination failed!");
    throw new Error("EC2 instance termination failed!");
  }

  console.log("EC2 instances termination initiated");
  configBody.TerminatingInstances.forEach(inst => {
    console.log("Instance " + inst.InstanceId + " state: " + inst.CurrentState.Name);
  });

  return configBody;
}
